INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-d0d1b9a2-moex-00015', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '乙公司於20X1年初給與8位高階主管各1,000單位，存續期間為10年的認股權。若公司股 價自目前每股$30上漲至$60，並且高階主管於股價目標達成時仍為在職，認股權將既得且可 立即行使。乙公司採用二項式選擇權定價模式，將股價於存續期間內達到目標及無法達成目 標的可能性納入考量，給與日的每單位認股權的估計公允價值為$15。此外，根據選擇權定價 模式在考量所有可能結果，達成股價目標的最可能期間在20X4年12月31日，亦即既得期 間為4年。乙公司於20X3年底估計於20X4年12月31日之前，將有2位高階主管離職。然 而，20X2年12月31日及20X4年12月31日各有一位及二位高階主管實際離職。實際達到 股價目標為20X5年12月31日，同年，另有一位高階主管離職。試問：有關上述認股權， 乙公司報導於20X4年度綜合損益表的「薪資費用」金額為何？', '["$7,500", "$15,000", "$18,750", "$22,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00016', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司帳列遞延所得稅皆按20%所得稅率計算。若該公司於X6年底應課稅暫時性差異的資 料如下，則X7年底遞延所得稅負債的期末總餘額為何？ ㉑與土地重估增值有關之暫時性差異$600,000，X7年底再次進行重估價，使該暫時性差異增 為$900,000。 ㉒與設備重估增值有關之暫時性差異$450,000；X7 年經折舊提列，使該暫時性差異減為 $360,000。 ㉓X5年初因吸收合併企業，而認列廉價購買利益$400,000，依稅法規定，合併取得消滅公司 可辨認淨資產公允價值超過收購成本部分，係自取得年度起分5年平均計入課稅所得。', '["$74,000", "$164,000", "$284,000", "$300,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00017', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '丁公司採用永續盤存制。20X1年度一批在途存貨 $50,000，交貨條件為起運點交貨，直至20X1 年底，丁公司並未收到廠商發票，故而會計人員並未記錄，並且，商品在20X1年底，並未運 送至丁公司，盤點存貨亦漏列；此外，20X1年度，由於會計人員的疏忽，折舊費用$3,500並 未提列並漏列此項記錄；再者，20X1年度寄銷一批商品（成本$65,000，售價$80,000）予他 公司，會計人員對於此項寄銷，記錄為賒銷。對於 20X1 年度的三項會計錯誤，會計人員於 20X2 年 1 月份察覺，進行錯誤更正的會計處理，此時，無須考慮所得稅影響。試問：20X2 年1月份的會計錯誤的更正，丁公司應借記或貸記「追溯適用及追溯重編之影響數」金額？', '["借記：$18,500", "借記：$83,500", "貸記：$31,500", "貸記：$111,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00018', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X6年底，與土地重估增值有關之暫時性差異為$300,000，X7年底再次重估，使該暫 時性差異增為$450,000。若該公司所得稅率為20%，則下列何者為X7年底與該土地重估增值 有關之正確會計分錄項目？', '["借：所得稅費用$30,000 貸：遞延所得稅資產$30,000", "借：其他綜合損益－遞延所得稅費用$30,000 貸：遞延所得稅負債$30,000", "借：遞延所得稅負債$30,000 貸：所得稅利益$30,000", "借：其他綜合損益－遞延所得稅費用$60,000 貸：遞延所得稅負債$60,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00019', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司X7年度稅前淨利為$500,000。若該公司有下列與課稅所得計算相關資料，則當年度課 稅所得的金額為何？ ㉑X7年超過稅法限額交際費用$20,000。 ㉒X7年認列兌換利益$30,000為外幣貨幣性資產產生之未實現利益，於實現時方須申報納稅， 預計X8年及X9年各實現50%。 ㉓預收X9年收入$40,000，應於X7年申報所得。 ㉔X7年認列研究支出$50,000，依稅法規定，應自X7年起分5年平均列為費用減除。', '["$530,000", "$550,000", "$570,000", "$630,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00020', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司移轉建築物予乙公司，並自乙公司租回該建築物，賣（承租）方及買（出租）方均適 用國際財務報導準則第16號「租賃」的相關規範進行移轉合約與租賃處理。此外，甲公司的 移轉建築物亦滿足國際財務報導準則第15號「客戶合約之收入」有關履約義務之規定，作為 銷售資產處理。然而，上述建築物的移轉售價低於移轉日的建築物的公允價值，甲公司會計 人員對於此項售價與公允價值的差額，應以何項會計科目記錄為宜？', '["其他長期借款", "未賺得融資收益", "使用權資產", "累計折舊－房屋及建築"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00021', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '乙公司於X2年1月1日向丙公司承租機器設備5年，每年底須支付租金$760,000，租賃契約 允許乙公司於租期屆滿時以$120,000購買該設備，且乙公司可合理預期將行使該購買選擇權。 設備於購買後仍可使用3年，估計最終殘值為$0。此外，乙公司在安排租賃過程中，發生初始 直接成本$90,000。若乙公司之增額借款利率為8%，則租賃開始日乙公司的租賃負債金額為何？ （註：年金現值，5期，8%=3.99271；年金現值，8期，8%=5.746639； 複利現值，5期，8%=0.680583；複利現值，8期，8%=0.540269）', '["$3,034,460", "$3,116,130", "$4,367,446", "$4,432,278"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00022', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司於20X1年1月1日以$500,000購買蘋果樹苗進行栽種，預期20X5年1月1日開始 結出果實，收成期間估計為50年，每年正常收成，殘值估計為零。20X1年及後續年度的薪 資及肥料等直接支出，每年為$80,000，自20X5年起，採收蘋果的支出，每年為$100,000。蘋 果為農產品，市場報價為$250,000，運費及出售成本約為$5,000。試問：20X5年12月31日 應認列「折舊費用」金額？', '["$0", "$9,259", "$16,400", "$196,400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00023', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-78566e18', 'sub-heelevel3-d0d1b9a2-01', NULL, 'single_choice', '甲公司採用確定福利計畫提供退休福利，X1 年相關資訊包括：當期服務成本$1,000、前期服務 成本$2,000、利息成本$3,000、計畫資產期初餘額$40,000、計畫資產實際報酬$3,000、精算利益 $2,000。若折現率與預期報酬率均為5%，則甲公司應列為X1年度其他綜合損益的金額為何？', '["$1,000", "$2,000", "$3,000", "$4,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:57+00:00", "source_pdf_sha1": "071c52ba44da", "answer_pdf_sha1": "8af944f1566d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "225", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00024', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-114-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'essay', '依據「中央政府普通公務單位會計制度之一致規定」，以第四級會計科目
